/*
	 SQL ID : ErpDAO.insertMessageMsgList
	 설  명 : 통합메시지 쪽지 목록 저장
*/
INSERT ALL 

	INTO TB_MESSAGE_MSG (
		  MSG_NO
		, MSG_SEQ
		, VWER_ID
		, USERNM
		, SYS_CD
		, ORG_ID
		, BUSS_GBN
		, SEND_RCV_GBN
		, SUBJECT
		, CTNT
		, SEND_DTTM
		, SNDR_PERS_NO
		, SNDR_DEPT_CD
		, SNDR_NM
		, FILE_NO
		, RGTR_ID
		, FRST_INQ_DTTM
		, RGTR_IP
		, MDFR_ID
		, MOD_DTTM
		, MOD_IP
		, COURSE_CD
	) VALUES (
		  #{item.msgNo}
		, #{item.msgSeq}
		, #{item.userId}
		, #{item.userNm}
		, #{item.sysCd}
		, #{item.orgId}
		, #{item.bussGbn}
		, #{item.sendRcvGbn}
		, NULL
		, #{item.ctnt}
		, SYSDATE
		, #{item.sndrPersNo}
		, #{item.sndrDeptCd}
		, #{item.sndrNm}
		, NULL
		, #{item.rgtrId}
		, SYSDATE
		, #{item.regIp}
		, #{item.rgtrId}
		, SYSDATE
		, #{item.regIp}
		, #{item.courseCd, jdbcType=VARCHAR}
	)

SELECT * FROM SYS.DUAL

