/*
	SQL ID : ErpDAO.insertMessageMsgLog
	설  명 : 통합메시지 쪽지 LOG 저장
*/
INSERT INTO TB_MESSAGE_MSG_LOG (
	  MSG_LOG_NO
	, MSG_NO
	, LOG_GBN
	, VWER_ID
	, USERNM
	, SYS_CD
	, ORG_ID
	, BUSS_GBN
	, SUBJECT
	, CTNT
	, SEND_DTTM
	, SNDR_PERS_NO
	, SNDR_DEPT_CD
	, SNDR_NM
	, FILE_NO
	, RCV_NUM
	, LOG_DESC
	, RGTR_ID
	, FRST_INQ_DTTM
