) VALUES (
	  #{msgLogNo}
	, #{msgNo}
	, 'S'
	, #{userId}
	, #{userNm}
	, #{sysCd}
	, #{orgId}
	, #{bussGbn}
	, NULL
	, #{ctnt}
	, SYSDATE
	, #{sndrPersNo}
	, #{sndrDeptCd}
	, #{sndrNm}
	, NULL
	, #{rcvNum}
	, #{logDesc}
	, #{rgtrId}
	, SYSDATE
	, #{regIp}
)

