/* SQL ID : ErpDAO.selectCourseEnrollmentAll 설 명 : 과목 수강 정보 전체 조회 */ SELECT STUDENT_ID , YEAR , SEMESTER , COURSE_CODE , SECTION , ATNDLC_APLYYN , AUDITYN , REG_DTTM , MOD_DTTM FROM UNI.LMS_ENROLLMENT_2023 WHERE 1 = 1
AND YEAR = #{year}
AND SEMESTER = #{semester}
AND ( COURSE_CODE || STUDENT_ID ) LIKE '%'||#{searchValue}||'%'

/* SQL ID : ErpDAO.selectLcdmsCntsPreview 설 명 : LCDMS 콘텐츠 미리보기 조회 */
SELECT * FROM ( SELECT YEAR , SEMESTER , GUBUN , CONT_CD , SBJCT_ID , SBJCTNM , SEQ_NAME , WEEK , LCTR_TOC_LRN_SCNDS FROM UNI.LMS_LCDMS_CNTS_PREVIEW_2023 WHERE 1 = 1 AND YEAR = #{year} AND SEMESTER = #{semester}
AND CONT_CD = #{contCd}
AND SBJCT_ID = #{scCd}
AND WEEK = #{week}
) A WHERE ROWNUM = 1

/* SQL ID : ErpDAO.listLcdmsPagePreview 설 명 : LCDMS 콘텐츠 페이지 미리보기 목록 조회 */ SELECT YEAR , SEMESTER , GUBUN , CONT_CD , SBJCT_ID , SBJCTNM , WEEK , ULD_GBNCD , PAGE_SEQNO , NVL(PAGENM,'강의') PAGENM , URL , LCTR_TOC_LRN_SCNDS , LMS_OPEN_YN , LMS_ATTEND_YN FROM UNI.LMS_LCDMS_PAGE_PREVIEW_2023 WHERE 1 = 1 AND YEAR = #{year} AND SEMESTER = #{semester}
AND CONT_CD = #{contCd}
AND SBJCT_ID = #{scCd}
AND WEEK = #{week}
ORDER BY WEEK, TO_NUMBER(PAGE_SEQNO)

