	/*
        SQL ID : ErpDAO.deleteTestScore 
                    설  명 : 테스트 성적 삭제
    */
    DELETE FROM LMS_STD_SCORE
    WHERE YR = #{yr}
    AND SMSTR_GBNCD = #{tmGbn}

    AND SBJCT_ID = #{scCd}
    AND DVCLAS_NO = #{ltNo}

