/*
    SQL ID : ErpDAO.callSpScorLmsMrksGet 
                설  명 : ERP 성적 메인 테이블로 이관하는 프로시저
*/
{call UNI.SP_SCOR_LMS_MRKS_GET (
      #{univGbn, 	mode=IN, jdbcType=VARCHAR}
    , #{yr, 		mode=IN, jdbcType=VARCHAR}
    , #{tmGbn, 		mode=IN, jdbcType=VARCHAR}
    , #{CRDTS_EXCH_UNVSTD_ID, 		mode=IN, jdbcType=VARCHAR}
    , #{inptId, 	mode=IN, jdbcType=VARCHAR}
    , #{inptIp, 	mode=IN, jdbcType=VARCHAR}
    , #{inptMenuId, mode=IN, jdbcType=VARCHAR}
    , #{outNum, 	mode=OUT, jdbcType=DECIMAL, javaType=Integer}
    , #{outMsg, 	mode=OUT, jdbcType=VARCHAR, javaType=java.lang.String}
)}

mapper.insert:

        /*
            SQL ID : insertSmsList
            설  명 : SMS 목록 저장
        */    
		INSERT INTO TB_MESSAGE_SMS (
		    SMS_NO              /* SMS 번호 */
		    , SMS_SEQ           /* SMS 순번 */
		    , VWER_ID           /* 사용자 번호 */
		    , USERNM           /* 사용자 이름 */
		    , SYS_CD            /* 시스템 코드 */
		    , ORG_ID            /* 기관 코드 */
		    , BUSS_GBN          /* 업무구분 */
		    , SEND_RCV_GBN      /* 수신 발신 구분 */
		    , SUBJECT           /* 제목 */
		    , CTNT              /* 내용 */
		    , SEND_DTTM         /* 발송 일시 */
		    , SNDR_PERS_NO      /* 발송자 개인번호 */
		    , SNDR_DEPT_CD      /* 발송자 부서 코드 */
		    , SNDR_NM           /* 발송자명 */
		    , SNDR_PHONE_NO     /* 발송자 전화번호 */
		    , RCV_PHONE_NO      /* 수신자 전화번호 */
		    , COURSE_CD         /* LMS과목코드 */
		    , RGTR_ID            /* 등록자 번호 */
		    , FRST_INQ_DTTM          /* 등록 일시 */
		    , RGTR_IP            /* 등록 IP */
		    , MDFR_ID            /* 수정자 번호 */
		    , MOD_DTTM          /* 수정 일시 */
		    , MOD_IP            /* 수정 IP */
		)

			SELECT
			    #{item.smsNo}
			    , #{item.smsSeq}
			    , #{item.userId}
			    , #{item.userNm}
			    , #{item.sysCd}
			    , #{item.orgId}
			    , #{item.bussGbn}
			    , #{item.sendRcvGbn}
			    , #{item.subject, jdbcType=VARCHAR}
			    , #{item.ctnt}
	            , SYSDATE
			    , #{item.sndrPersNo}
			    , #{item.sndrDeptCd}
			    , #{item.sndrNm}
			    , #{item.sndrPhoneNo}
			    , #{item.rcvPhoneNo, jdbcType=VARCHAR}
			    , #{item.courseCd, jdbcType=VARCHAR}
			    , #{item.rgtrId}
			    , SYSDATE
			    , #{item.regIp}
			    , #{item.mdfrId}
			    , SYSDATE
			    , #{item.modIp}
			FROM DUAL


        /*
            SQL ID : insertAcademicSmsPushReceive 
            설  명 : ERP SMS, PUSH 받는 정보 저장
        */    
        INSERT INTO BSNS111 (       
            SEND_NO                 /* 발송번호 */
            , SEND_SEQ              /* 발송순번 */
            , RECPR_PERS_NO         /* 수신자개인번호 */
            , RECPR_NM              /* 수신자명 */
            , RECPR_HANDP_NO        /* 수신자휴대전화번호 */
            , SEND_DTTM             /* 발송일시 */
            , SMS_SEND_RSLT_CTNT    /* SMS발송결과내용 */
            , PUSH_SEND_RSLT_CTNT   /* PUSH발송결과내용 */
            , SMS_CTNT              /* SMS내용 */
            , PUSH_CTNT             /* PUSH내용 */
            , INPT_ID               /* 입력ID */
            , INPT_DTTM             /* 입력일시 */
            , INPT_IP               /* 입력IP */
            , INPT_MENU_ID          /* 입력메뉴ID */
            , MOD_ID                /* 수정ID */
            , MOD_DTTM              /* 수정일시 */
            , MOD_IP                /* 수정IP */
            , MOD_MENU_ID           /* 수정메뉴ID */
            , REF_MSG_IF_ID         /* 참조메세지ID */
            , CFM_YN                /* 확인여부 */
        )

        	SELECT
	            #{item.sendNo}
	            , #{item.sendSeq}
	            , #{item.recprPersNo}
	            , #{item.recprNm}
	            , #{item.recprHandpNo}

	            , TO_DATE(#{item.sendDttm}, 'YYYY-MM-DD HH24:MI')


	            , SYSDATE + (INTERVAL '5' SECOND)

	            , #{item.smsSendRsltCtnt}
	            , #{item.pushSendRsltCtnt}
	            , #{item.smsCtnt}
	            , #{item.pushCtnt}
	            , #{item.inptId}
	            , SYSTIMESTAMP
	            , #{item.inptIp}
	            , #{item.inptMenuId}
	            , #{item.modId}
	            , SYSTIMESTAMP
	            , #{item.modIp}
	            , #{item.modMenuId}
	            , #{item.refMsgIfId}
	            , #{item.cfmYn}
        	FROM DUAL
